        backgroundColor: semantics.light.neutral.background.primary,
        boxShadow: `0 ${semantics.units.space.componentLayout.xxs} ${semantics.units.space.componentLayout.xs} ${semantics.light.neutral.border.default}`,
        fontSize: '1.25rem',
        height: '2rem',
        margin: `0 ${semantics.units.space.componentLayout.xs}`,
        pointerEvents: 'auto',
        width: '2rem',
        zIndex: 1,
