              width: '2.5rem',
              height: '2.5rem',
              margin: '0',
              border: `${semantics.units.borderWidth.default} solid ${semantics.light.interactive.border.weak}`,
              boxShadow: 'none',
              svg: {
                fill: semantics.light.interactive.icon.subtle
              }
            }
          : {})
      },
      alignItems: 'center',
      bottom: 0,
      display: 'flex',
      justifyContent: 'space-between',
      left: 0,
      position: 'absolute',
      right: 0,
      top: 0,
      ...(separatedView
        ? {
            left: 'inherit',
            bottom: 'inherit',
            top: `-${semantics.units.space.pageLayout.xl}`,
            gap: semantics.units.space.componentLayout.sm,
            '@media screen and (max-width: 699px)': {
              display: 'none !important'
            }
          }
        : {})
    },
    '.keen-slider': {
      display: 'flex !important',
      height: '100%',
      overflow: 'hidden !important',
      position: 'relative',
      touchAction: 'pan-y',
      userSelect: 'none',
      WebkitTouchCallout: 'none'
    },
    '.keen-slider__slide': {
      minHeight: '100%',
      overflow: 'hidden',
      position: 'relative',
      width: '100%'
    },
    backgroundColor: 'transparent',
    height: '100%',
    overflow: 'hidden',
    position: 'relative',
    width: '100%',
    ...(separatedView ? {overflow: 'visible'} : {})
  },
  display: 'flex',
  height: 'max-content',
  position: 'relative',
  width: '100%'
}));

const getSlidesPerView = (breakpoint) => {
  if (breakpoint === 'sm') {
    return 2.25;
  }
  if (breakpoint === 'md') {
    return 3.5;
  }
  return 4;
};

const CarouselCardsView = ({
  children,
  separatedView,
  onLeftClick,
  onRightClick
}) => {
  const breakpoint = useBreakpoint();
  const gap = breakpoint === 'sm' ? 8 : 16;
  const slidesPerView = getSlidesPerView(breakpoint);

  const [sliderLoaded, setSliderLoaded] = useState(false);
  const [currentSlide, setCurrentSlide] = useState(0);
