        if (onLeftClick) {
          onLeftClick();
        } else {
          fireTabbedViewEvent({
            arrowDirection: 'previous',
            eventType: EVENT_TYPE.ARROW_CLICKED
          });
        }
        instanceRef.prev();
      }
    },
    [instanceRef, onLeftClick]
  );

  const handleRightClick = useCallback(
    (e) => {
      e.stopPropagation();
      if (instanceRef && instanceRef.next) {
        if (onRightClick) {
          onRightClick();
        } else {
          fireTabbedViewEvent({
            arrowDirection: 'next',
            eventType: EVENT_TYPE.ARROW_CLICKED
          });
        }
        instanceRef.next();
      }
    },
    [instanceRef, onRightClick]
  );

  const showArrows = children.length >= 2;

  return (
    <CarouselContainer
      separatedView={separatedView}
      sx={{
        '.arrow': {
          '&::before': {
            bottom: `-${semantics.units.space.componentLayout.sm}`,
            content: '""',
            left: `-${semantics.units.space.componentLayout.sm}`,
            position: 'absolute',
            right: `-${semantics.units.space.componentLayout.sm}`,
            top: `-${semantics.units.space.componentLayout.sm}`,
            zIndex: 1
          },
          position: 'relative',
          top: 'unset'
        },
        '.keen-slider__slide': {
          '& .MuiCard-root:hover': {
            boxShadow: 'none !important'
          }
        },
        '.left': {
          left: separatedView ? '0' : semantics.units.space.componentLayout.xs
        },
        '.right': {
          right: separatedView ? '0' : semantics.units.space.componentLayout.xs
        },
        display: 'block',
        margin: 'auto',
        width: '100%'
      }}>
      <div className="slider" ref={boundingBoxRef}>
        {showArrows && sliderLoaded && (
          <div className="arrow-container">
            <IconButton
              disableRipple
              className={`arrow left${isFirstSlide ? ' disabled' : ''}`}
              disabled={isFirstSlide}
              onClick={handleLeftClick}
              aria-label="Previous products"
              data-testid="pdp-rfy-previous-arrow">
              <ArrowDownIcon
                sx={{fill: semantics.light.interactive.icon.subtle}}
                fontSize="inherit"
              />
            </IconButton>

            <IconButton
              disableRipple
              className={`arrow right${isLastSlide ? ' disabled' : ''}`}
              disabled={isLastSlide}
              onClick={handleRightClick}
              aria-label="Next products"
              data-testid="pdp-rfy-next-arrow">
              <ArrowDownIcon
                sx={{fill: semantics.light.interactive.icon.subtle}}
                fontSize="inherit"
              />
            </IconButton>
          </div>
        )}
        <div ref={keenSliderCallbackRef} className="keen-slider">
          {children.map((slide, i) => (
            <div
              key={slide.key}
              className={`keen-slider__slide slide-${i}`}
              style={{cursor: 'grab'}}>
              {slide}
            </div>
          ))}
        </div>
      </div>
    </CarouselContainer>
  );
};

CarouselCardsView.propTypes = {
  children: PropTypes.node.isRequired,
  separatedView: PropTypes.bool.isRequired
};

export default CarouselCardsView;

