import {
  EVENT_TYPE,
  fireTabbedViewEvent
} from 'utils/metrics/pdpRelatedStylesTabbedView';

const CarouselContainer = styled('div')(({separatedView}) => ({
  '.slider': {
    '.arrow-container': {
      '.arrow': {
        '&.disabled': {
          backgroundColor: 'transparent',
          boxShadow: 'none',
          cursor: 'default'
        },
        '&.left svg': {transform: 'rotate(90deg) !important;'},
        '&.right svg': {transform: 'rotate(-90deg);'},
        '&:active': {
          backgroundColor: semantics.light.interactive.background.weak
        },
        '&:hover': {
          backgroundColor: semantics.light.neutral.background.subtleOpaque
        },
        backgroundColor: semantics.light.neutral.background.primary,
        boxShadow: `0 ${semantics.units.space.componentLayout.xxs} ${semantics.units.space.componentLayout.xs} ${semantics.light.neutral.border.default}`,
        fontSize: '1.25rem',
        height: '2rem',
        margin: `0 ${semantics.units.space.componentLayout.xs}`,
        pointerEvents: 'auto',
        width: '2rem',
        zIndex: 1,
        ...(separatedView
          ? {
              width: '2.5rem',
              height: '2.5rem',
              margin: '0',
              border: `${semantics.units.borderWidth.default} solid ${semantics.light.interactive.border.weak}`,
              boxShadow: 'none',
              svg: {
                fill: semantics.light.interactive.icon.subtle
              }
            }
          : {})
      },
      alignItems: 'center',
      bottom: 0,
      display: 'flex',
      justifyContent: 'space-between',
      left: 0,
      position: 'absolute',
      right: 0,
      top: 0,
      ...(separatedView
        ? {
            left: 'inherit',
            bottom: 'inherit',
            top: `-${semantics.units.space.pageLayout.xl}`,
            gap: semantics.units.space.componentLayout.sm,
            '@media screen and (max-width: 699px)': {
              display: 'none !important'
            }
          }
        : {})
    },
    '.keen-slider': {
      display: 'flex !important',
      height: '100%',
      overflow: 'hidden !important',
      position: 'relative',
      touchAction: 'pan-y',
      userSelect: 'none',
      WebkitTouchCallout: 'none'
    },
    '.keen-slider__slide': {
      minHeight: '100%',
      overflow: 'hidden',
      position: 'relative',
      width: '100%'
    },
    backgroundColor: 'transparent',
    height: '100%',
    overflow: 'hidden',
    position: 'relative',
    width: '100%',
    ...(separatedView ? {overflow: 'visible'} : {})
  },
  display: 'flex',
  height: 'max-content',
  position: 'relative',
  width: '100%'
}));

const getSlidesPerView = (breakpoint) => {
  if (breakpoint === 'sm') {
    return 2.25;
  }
  if (breakpoint === 'md') {
    return 3.5;
  }
  return 4;
};

const CarouselCardsView = ({
  children,
  separatedView,
  onLeftClick,
  onRightClick
}) => {
  const breakpoint = useBreakpoint();
  const gap = breakpoint === 'sm' ? 8 : 16;
  const slidesPerView = getSlidesPerView(breakpoint);

  const [sliderLoaded, setSliderLoaded] = useState(false);
  const [keenSliderCallbackRef, instanceRef] = useKeenSlider(
    {
      created: () => {
        setSliderLoaded(true);
      },
      initial: 0,
      loop: children.length > slidesPerView,
      mode: 'snap',
      slidesPerView,
      spacing: gap
    },
    [slidesPerView, gap]
  );

  const boundingBoxRef = useRef(null);
  useResizeObserver(boundingBoxRef, () => instanceRef?.refresh());

  const handleLeftClick = useCallback(
    (e) => {
      e.stopPropagation();
      if (instanceRef && instanceRef.prev) {
        if (onLeftClick) {
          onLeftClick();
        } else {
          fireTabbedViewEvent({
            arrowDirection: 'previous',
            eventType: EVENT_TYPE.ARROW_CLICKED
          });
        }
        instanceRef.prev();
      }
    },
    [instanceRef, onLeftClick]
  );

  const handleRightClick = useCallback(
    (e) => {
      e.stopPropagation();
      if (instanceRef && instanceRef.next) {
        if (onRightClick) {
          onRightClick();
        } else {
          fireTabbedViewEvent({
            arrowDirection: 'next',
            eventType: EVENT_TYPE.ARROW_CLICKED
          });
        }
        instanceRef.next();
      }
    },
    [instanceRef, onRightClick]
  );

  const showArrows = children.length >= 2;

  return (
    <CarouselContainer
      separatedView={separatedView}
      sx={{
        '.arrow': {
          '&::before': {
            bottom: `-${semantics.units.space.componentLayout.sm}`,
            content: '""',
            left: `-${semantics.units.space.componentLayout.sm}`,
            position: 'absolute',
            right: `-${semantics.units.space.componentLayout.sm}`,
            top: `-${semantics.units.space.componentLayout.sm}`,
            zIndex: 1
          },
          position: 'relative',
          top: 'unset'
        },
        '.keen-slider__slide': {
          '& .MuiCard-root:hover': {
            boxShadow: 'none !important'
          }
        },
        '.left': {
          left: separatedView ? '0' : semantics.units.space.componentLayout.xs
        },
        '.right': {
          right: separatedView ? '0' : semantics.units.space.componentLayout.xs
        },
        display: 'block',
        margin: 'auto',
        width: '100%'
      }}>
      <div className="slider" ref={boundingBoxRef}>
        {showArrows && sliderLoaded && (
          <div className="arrow-container">
            <IconButton
              disableRipple
              className={`arrow left${isFirstSlide ? ' disabled' : ''}`}
              disabled={isFirstSlide}
              onClick={handleLeftClick}
              aria-label="Previous products"
              data-testid="pdp-rfy-previous-arrow">
              <ArrowDownIcon
                sx={{fill: semantics.light.interactive.icon.subtle}}
                fontSize="inherit"
              />
            </IconButton>

            <IconButton
              disableRipple
              className={`arrow right${isLastSlide ? ' disabled' : ''}`}
              disabled={isLastSlide}
              onClick={handleRightClick}
              aria-label="Next products"
              data-testid="pdp-rfy-next-arrow">
              <ArrowDownIcon
                sx={{fill: semantics.light.interactive.icon.subtle}}
                fontSize="inherit"
              />
            </IconButton>
          </div>
        )}
        <div ref={keenSliderCallbackRef} className="keen-slider">
          {children.map((slide, i) => (
            <div
              key={slide.key}
              className={`keen-slider__slide slide-${i}`}
              style={{cursor: 'grab'}}>
              {slide}
            </div>
          ))}
        </div>
      </div>
    </CarouselContainer>
  );
};

CarouselCardsView.propTypes = {
  children: PropTypes.node.isRequired,
  separatedView: PropTypes.bool.isRequired
};

export default CarouselCardsView;

