"use client";

import { Box } from "@customink/pigment-react";
import IconButton from "@/components/ui/icon-button/icon-button";
import ArrowDownIcon from "@/components/ui/icons/arrow-down-icon";
import { ReactNode, useState, useEffect, useCallback, useMemo } from "react";
import styles from "./carousel-cards-view.module.css";
import { pdpRecommendations } from "@/lib/analytics/events/pdp";

const SLIDES_PER_VIEW = 4;
const SLIDE_WIDTH = 100 / SLIDES_PER_VIEW; // 25%

interface CarouselCardsViewProps {
  children: ReactNode[];
}

export default function CarouselCardsView({ children }: CarouselCardsViewProps) {
  const total = children.length;
  const [index, setIndex] = useState(0);
  const [animate, setAnimate] = useState(true);
  const [isAnimating, setIsAnimating] = useState(false);

  // Reset position when content changes (tab switch)
  useEffect(() => {
    setAnimate(false);
    setIndex(0);
  }, [total]);

  // Re-enable transitions after an instant jump
  useEffect(() => {
    if (!animate) {
      requestAnimationFrame(() => {
        requestAnimationFrame(() => {
          setAnimate(true);
          setIsAnimating(false);
        });
      });
    }
  }, [animate]);

  // Clone slides at edges for seamless looping:
  // [last N clones] [real slides] [first N clones]
  const slides = useMemo(
    () => [
      ...children.slice(-SLIDES_PER_VIEW).map((child, i) => ({ child, key: `clone-end-${i}` })),
      ...children.map((child, i) => ({ child, key: `real-${i}` })),
      ...children.slice(0, SLIDES_PER_VIEW).map((child, i) => ({ child, key: `clone-start-${i}` })),
    ],
    [children],
  );

  // Offset accounts for the prepended clones
  const trackOffset = (index + SLIDES_PER_VIEW) * SLIDE_WIDTH;

  const handleTransitionEnd = useCallback(
    (e: React.TransitionEvent) => {
      if (e.target !== e.currentTarget) return;
      setIsAnimating(false);
      if (index >= total) {
        setAnimate(false);
        setIndex(index % total);
      } else if (index < 0) {
        setAnimate(false);
        setIndex(((index % total) + total) % total);
      }
    },
    [index, total],
  );

  const handlePrev = (e: React.MouseEvent): void => {
    if (isAnimating) return;
    e.stopPropagation();
    setIsAnimating(true);
    pdpRecommendations.tabbedViewArrowClick("prev");
    setIndex((prev) => prev - 1);
  };

  const handleNext = (e: React.MouseEvent): void => {
    if (isAnimating) return;
    e.stopPropagation();
    setIsAnimating(true);
    pdpRecommendations.tabbedViewArrowClick("next");
    setIndex((prev) => prev + 1);
  };

  const showArrows = total > SLIDES_PER_VIEW;

  return (
    <Box className={styles.carouselWrapper} data-testid="pdp-reco-carousel">
      {showArrows && (
        <Box display="flex" className={styles.arrowOverlay}>
          <IconButton
            aria-label="Previous slide"
            onClick={handlePrev}
            className={styles.arrowBtn}
            data-testid="pdp-reco-carousel-prev"
          >
            <ArrowDownIcon className={styles.arrowPrev} />
          </IconButton>

          <IconButton
            aria-label="Next slide"
            onClick={handleNext}
            className={styles.arrowBtn}
            data-testid="pdp-reco-carousel-next"
          >
            <ArrowDownIcon className={styles.arrowNext} />
          </IconButton>
        </Box>
      )}

      <Box className={styles.viewport}>
        <Box
          className={styles.track}
          style={{
            transform: `translateX(-${trackOffset}%)`,
            transition: animate ? "transform 0.6s ease" : "none",
          }}
          onTransitionEnd={handleTransitionEnd}
        >
          {slides.map(({ child, key }) => {
            const isClone = key.startsWith("clone-");
            return (
              <Box
                key={key}
                className={styles.slide}
                {...(isClone ? { "aria-hidden": true, tabIndex: -1 } : {})}
              >
                {child}
              </Box>
            );
          })}
        </Box>
      </Box>
    </Box>
  );
}

