describe('arrow accessibility', () => {
  let createdCallback;

  beforeEach(() => {
    jest.useFakeTimers();
    createdCallback = null;

    mockUseKeenSlider.mockImplementation((_options, plugins) => {
      if (plugins && plugins[0]) {
        const fakeSlider = {
          on: (event, cb) => {
            if (event === 'created') createdCallback = cb;
          }
        };
        plugins[0](fakeSlider);
      }
      return [
        jest.fn(),
        {
          current: {
            next: jest.fn(),
            prev: jest.fn(),
            update: jest.fn()
          }
        }
      ];
    });
  });

  afterEach(() => {
    jest.useRealTimers();
  });

  const renderWithSliderCreated = () => {
    const result = render(
      <CarouselCardsView>{mockChildren}</CarouselCardsView>
    );
    if (createdCallback) {
      createdCallback();
    }
    result.rerender(
      <CarouselCardsView>{mockChildren}</CarouselCardsView>
    );
    return result;
  };

  it('renders arrow buttons with aria-labels', () => {
    renderWithSliderCreated();

    expect(
      screen.getByLabelText('Previous products')
    ).toBeInTheDocument();
    expect(screen.getByLabelText('Next products')).toBeInTheDocument();
  });

  it('renders arrow buttons with data-testid attributes', () => {
    renderWithSliderCreated();

    expect(
      screen.getByTestId('pdp-rfy-previous-arrow')
    ).toBeInTheDocument();
    expect(
      screen.getByTestId('pdp-rfy-next-arrow')
    ).toBeInTheDocument();
  });
});

