import '@testing-library/jest-dom';
import {render, screen} from '@testing-library/react';
import React from 'react';
import useBreakpoint from 'hooks/useBreakpoint';
import CarouselCardsView from './CarouselCardsView';

jest.mock('hooks/useBreakpoint');
jest.mock('@react-hook/resize-observer');

jest.mock('keen-slider/react', () => ({
  useKeenSlider: jest.fn()
}));

const {useKeenSlider} = require('keen-slider/react');

const mockUseKeenSlider = useKeenSlider;

const mockChildren = [
  <div key="1" data-testid="slide-1">
    Slide 1
  </div>,
  <div key="2" data-testid="slide-2">
    Slide 2
  </div>,
  <div key="3" data-testid="slide-3">
    Slide 3
  </div>,
  <div key="4" data-testid="slide-4">
    Slide 4
  </div>,
  <div key="5" data-testid="slide-5">
    Slide 5
  </div>
];

describe('CarouselCardsView', () => {
  beforeEach(() => {
    useBreakpoint.mockReturnValue('lg');

    mockUseKeenSlider.mockImplementation(() => {
      return [
        jest.fn(),
        {
          current: {
            next: jest.fn(),
            prev: jest.fn(),
            update: jest.fn()
          }
        }
      ];
    });
  });

  afterEach(() => {
    jest.clearAllMocks();
    jest.restoreAllMocks();
  });

  it('renders all slides', () => {
    render(<CarouselCardsView>{mockChildren}</CarouselCardsView>);

    expect(screen.getByTestId('slide-1')).toBeInTheDocument();
    expect(screen.getByTestId('slide-2')).toBeInTheDocument();
    expect(screen.getByTestId('slide-3')).toBeInTheDocument();
    expect(screen.getByTestId('slide-4')).toBeInTheDocument();
    expect(screen.getByTestId('slide-5')).toBeInTheDocument();
  });

  it('renders carousel container', () => {
    render(<CarouselCardsView>{mockChildren}</CarouselCardsView>);

    const slider = screen.getByTestId('slide-1').closest('.keen-slider');
    expect(slider).toBeInTheDocument();
  });

  it('shows arrows when there are 2 or more slides', () => {
    expect(mockChildren.length).toBeGreaterThanOrEqual(2);

    render(<CarouselCardsView>{mockChildren}</CarouselCardsView>);

    const slider = screen.getByTestId('slide-1').closest('.keen-slider');
    expect(slider).toBeInTheDocument();
  });

  it('handles left arrow click', () => {
    const mockPrev = jest.fn();
    mockUseKeenSlider.mockImplementation(() => {
      return [
        jest.fn(),
        {
          current: {
            next: jest.fn(),
            prev: mockPrev,
            update: jest.fn()
          }
        }
      ];
    });

    expect(mockPrev).toBeDefined();

    render(<CarouselCardsView>{mockChildren}</CarouselCardsView>);

    expect(screen.getByTestId('slide-1')).toBeInTheDocument();
  });

  it('handles right arrow click', () => {
    const mockNext = jest.fn();
    mockUseKeenSlider.mockImplementation(() => {
      return [
        jest.fn(),
        {
          current: {
            next: mockNext,
            prev: jest.fn(),
            update: jest.fn()
          }
        }
      ];
    });

    expect(mockNext).toBeDefined();

    render(<CarouselCardsView>{mockChildren}</CarouselCardsView>);

    expect(screen.getByTestId('slide-1')).toBeInTheDocument();
  });

  it('prevents event bubbling on arrow clicks', () => {
    const mockPrev = jest.fn();
    const mockNext = jest.fn();
    mockUseKeenSlider.mockImplementation(() => {
      return [
        jest.fn(),
        {
          current: {
            next: mockNext,
            prev: mockPrev,
            update: jest.fn()
          }
        }
      ];
    });

    const containerClickHandler = jest.fn();

    render(
      <div onClick={containerClickHandler}>
        <CarouselCardsView>{mockChildren}</CarouselCardsView>
      </div>
    );

    expect(screen.getByTestId('slide-1')).toBeInTheDocument();
    expect(containerClickHandler).not.toHaveBeenCalled();
  });

  it('uses correct gap for small breakpoint', () => {
    useBreakpoint.mockReturnValue('sm');

    render(<CarouselCardsView>{mockChildren}</CarouselCardsView>);

    expect(mockUseKeenSlider).toHaveBeenCalledWith(
      expect.objectContaining({
        slides: expect.objectContaining({spacing: 8})
      }),
      expect.any(Array)
    );
  });

  it('uses correct gap for large breakpoint', () => {
    useBreakpoint.mockReturnValue('lg');

    render(<CarouselCardsView>{mockChildren}</CarouselCardsView>);

    expect(mockUseKeenSlider).toHaveBeenCalledWith(
      expect.objectContaining({
        slides: expect.objectContaining({spacing: 16})
      }),
      expect.any(Array)
    );
  });

  it('renders with single slide', () => {
    const singleSlide = [
      <div key="1" data-testid="single-slide">
        Single Slide
      </div>
    ];

    render(<CarouselCardsView>{singleSlide}</CarouselCardsView>);

    expect(screen.getByTestId('single-slide')).toBeInTheDocument();
  });

  it('applies cursor grab style to slides', () => {
    render(<CarouselCardsView>{mockChildren}</CarouselCardsView>);

    const slideContainer = screen.getByTestId('slide-1').parentElement;
    expect(slideContainer).toHaveStyle('cursor: grab');
  });

  it('initializes keen slider with correct options', () => {
    render(<CarouselCardsView>{mockChildren}</CarouselCardsView>);

    expect(mockUseKeenSlider).toHaveBeenCalledWith(
      expect.objectContaining({
        initial: 0,
        loop: true,
        mode: 'snap',
        slides: {perView: 4, spacing: 16}
      }),
      expect.any(Array)
    );
  });

  it('generates unique slide keys', () => {
    render(<CarouselCardsView>{mockChildren}</CarouselCardsView>);

    const slides = screen.getAllByTestId(/slide-\d/);
    expect(slides).toHaveLength(5);

    slides.forEach((slide, index) => {
      expect(slide.parentElement).toHaveClass(`slide-${index}`);
    });
  });

  it('handles empty children array', () => {
    render(<CarouselCardsView>{[]}</CarouselCardsView>);

    const slider = document.querySelector('.keen-slider');
    expect(slider).toBeInTheDocument();
    expect(slider.children).toHaveLength(0);
  });

  describe('arrow accessibility', () => {
    beforeEach(() => {
      mockUseKeenSlider.mockImplementation((options, plugins) => {
        if (plugins && plugins[0]) {
          const fakeSlider = {on: (event, cb) => event === 'created' && cb()};
          plugins[0](fakeSlider);
        }
        return [
          jest.fn(),
          {
            current: {
              next: jest.fn(),
              prev: jest.fn(),
              update: jest.fn()
            }
          }
        ];
      });
    });

    it('renders arrow buttons with aria-labels', () => {
      render(<CarouselCardsView>{mockChildren}</CarouselCardsView>);

      expect(screen.getByLabelText('Previous products')).toBeInTheDocument();
      expect(screen.getByLabelText('Next products')).toBeInTheDocument();
    });

    it('renders arrow buttons with data-testid attributes', () => {
      render(<CarouselCardsView>{mockChildren}</CarouselCardsView>);

      expect(screen.getByTestId('pdp-rfy-previous-arrow')).toBeInTheDocument();
      expect(screen.getByTestId('pdp-rfy-next-arrow')).toBeInTheDocument();
    });
  });
});

